function solve(nums1) {
    const n = nums1.length;

    // Helper function to check if all numbers in an array have the same parity
    const checkParity = (nums2) => {
        if (nums2.length === 0) return true;
        const parity = Math.abs(nums2[0] % 2); // 0 for even, 1 for odd
        for (let i = 1; i < nums2.length; i++) {
            if (Math.abs(nums2[i] % 2) !== parity) {
                return false;
            }
        }
        return true;
    };

    // Since N is small (up to 100), we can try to iterate over all possible combinations.
    // However, the number of choices for each element is N (N choices for the subtraction) + 1 (for nums1[i]).
    // The total number of combinations is (N+1)^N, which is too large if N=100.
    // We must find a structural property.

    // The parity of nums2[i] depends on:
    // 1. If nums2[i] = nums1[i]: parity is parity(nums1[i])
    // 2. If nums2[i] = nums1[i] - nums1[j]: parity is parity(nums1[i] - nums1[j]) = parity(nums1[i]) XOR parity(nums1[j])

    // Let P_i be the parity of nums1[i] (0 for even, 1 for odd).

    // We need to check two target parities: All Even (0) or All Odd (1).

    // --- Check if an all-Even array (Target Parity = 0) is possible ---
    let possible_all_even = true;

    // If we fix the choice for one element, it might constrain others, but since the choices are coupled
    // via subtraction, we might still need dynamic programming or a search, but let's re-examine the constraint.

    // For each i, we need to find a choice such that the resulting parity is 0.
    // Choice 1: nums2[i] = nums1[i]. Required: P_i = 0.
    // Choice 2: nums2[i] = nums1[i] - nums1[j]. Required: P_i XOR P_j = 0, so P_i = P_j.

    // If for a specific i, both options lead to a non-zero parity, then it's impossible to make nums2[i] even.
    // But wait, we must pick ONE choice for nums2[i], and ALL resulting nums2[i] must be even.

    // Since the choice for nums2[i] (which j to pick for subtraction, or if we don't subtract) affects only nums2[i],
    // the constraints are independent for each i IF we only care about the target parity.

    // If we aim for all even (Target = 0):
    // For each i, can we make nums2[i] even?
    let can_be_all_even = true;
    for (let i = 0; i < n; i++) {
        const Pi = nums1[i] % 2;
        let can_make_even = false;

        // Option 1: nums2[i] = nums1[i]. Is Pi = 0?
        if (Pi === 0) {
            can_make_even = true;
        }

        // Option 2: nums2[i] = nums1[i] - nums1[j], j != i. Is Pi XOR Pj = 0 (i.e., Pi = Pj)?
        // We need at least one j != i such that Pj = Pi.
        if (!can_make_even) {
            for (let j = 0; j < n; j++) {
                if (i === j) continue;
                const Pj = nums1[j] % 2;
                if (Pi === Pj) {
                    can_make_even = true;
                    break;
                }
            }
        }

        if (!can_make_even) {
            can_be_all_even = false;
            break;
        }
    }

    if (can_be_all_even) return true;


    // --- Check if an all-Odd array (Target Parity = 1) is possible ---

    // For each i, can we make nums2[i] odd?
    let can_be_all_odd = true;
    for (let i = 0; i < n; i++) {
        const Pi = nums1[i] % 2;
        let can_make_odd = false;

        // Option 1: nums2[i] = nums1[i]. Is Pi = 1?
        if (Pi === 1) {
            can_make_odd = true;
        }

        // Option 2: nums2[i] = nums1[i] - nums1[j], j != i. Is Pi XOR Pj = 1 (i.e., Pi != Pj)?
        // We need at least one j != i such that Pj != Pi.
        if (!can_make_odd) {
            for (let j = 0; j < n; j++) {
                if (i === j) continue;
                const Pj = nums1[j] % 2;
                if (Pi !== Pj) {
                    can_make_odd = true;
                    break;
                }
            }
        }

        if (!can_make_odd) {
            can_be_all_odd = false;
            break;
        }
    }

    return can_be_all_odd;
}

